mapper.select:
SELECT COUNT(1)
FROM student_assessment_semester_summary
WHERE student_id = #{studentId}
  AND semester = #{semester}
  AND semester_level = #{semesterLevel}

SELECT s.student_id AS studentId, s.name AS name, s.college AS college, s.class_name AS className, s.grade AS grade, s.phone AS phone, s.password AS password, s.avatar_url AS avatarUrl FROM student_assessment_semester_summary ss JOIN student s ON ss.student_id = s.student_id WHERE ss.semester = #{semester} AND ss.semester_level = '危险' AND s.class_name IN
#{className}
ORDER BY ss.last_tested_at DESC, s.student_id ASC LIMIT #{offset}, #{pageSize}
